import './App.css';
import React, { useEffect, useState } from 'react';
import axios from 'axios';
import io from 'socket.io-client';
import adImage from './images/adImage.png';
import { useRef } from 'react';
import discoverylogo from "./images/discoverylogo.png";
import natgeologo from "./images/natgeologo.png";
import codelogo from "./images/codelogo-2.png";
// import billgatesfoundation from "./images/billgatesfoundation.png"
import billlogo from "./images/billlogo.png"
import khanlogo from "./images/khanlogo.png";
import ww1logo from "./images/ww1logo.png"
import ww2logo from "./images/ww2logo.png"
import ww3logo from "./images/ww3logo.png"
// import ww4logo from "./images/ww4logo.png"
// import ww5logo from "./images/ww5logo.png"


// const socket = io('http://localhost:5001');
const socket = io(process.env.LOCAL_SERVER_API);
// const socket = io('https://whatwhys.com/');

// const categoriesList = ['General', 'History', 'Math', 'Political', 'Literature'];
const categoriesList = ['General', 'History', 'Math', 'Literature'];

const App = () => {
  const [questions, setQuestions] = useState([]);
  // const [category, setCategory] = useState('General');
  const [solvedQuestions, setSolvedQuestions] = useState([]);
  const [selectedAnswers, setSelectedAnswers] = useState({});
  const [selectedCategories, setSelectedCategories] = useState(['General']);
  const [cursors, setCursors] = useState({});
  const username = useRef(`User_${Math.random().toString(36).substring(2, 6)}`);

  useEffect(() => {
    const fetchQuestions = async () => {
      try {
        const res = await axios.get('/api/questions', {
          params: { categories: selectedCategories.join(',') },
        });
        setQuestions(res.data);
      } catch (error) {
        console.error('Error fetching questions:', error);
      }
    };



    const fetchSolvedState = async () => {
      try {
        const res = await axios.get('/api/solved');
        const solvedData = res.data || [];

        setSolvedQuestions(solvedData.map(item => item.questionId));

        const initialSelectedAnswers = {};
        solvedData.forEach(({ questionId, selectedAnswer }) => {
          initialSelectedAnswers[questionId] = selectedAnswer;
        });

        setSelectedAnswers(initialSelectedAnswers);

      } catch (error) {
        console.error('Error fetching solved state:', error);
      }
    };

    fetchQuestions();
    fetchSolvedState();

    socket.on('updateSolved', (data) => {
      setSolvedQuestions((prevState) => {
        if (!prevState.includes(data.questionId)) {
          return [...prevState, data.questionId];
        }
        return prevState;
      });
    });

    return () => {
      socket.off('updateSolved');
    };

  }, [selectedCategories]);

  useEffect(() => {
    const handleMouseMove = (event) => {
      const { clientX, clientY } = event;
      socket.emit('cursorMove', { x: clientX, y: clientY, username: username.current });
    };

    window.addEventListener('mousemove', handleMouseMove);

    socket.on('cursorsUpdate', (newCursors) => {
      setCursors(newCursors); // Make sure this line is present
    });

    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      socket.off('cursorsUpdate');
    };
  }, []);

  // const socket = io('http://localhost:5001');

  socket.on('connect', () => {
    console.log('Connected to server');
  });



  const handleCategoryChange = (category) => {
    setSelectedCategories((prev) =>
      prev.includes(category)
        ? prev.filter((cat) => cat !== category)
        : [...prev, category]
    );
  };


  const handleAnswerChange = async (questionId, optionIndex) => {
    setSelectedAnswers({
      ...selectedAnswers,
      [questionId]: optionIndex,
    });

    const question = questions.find(q => q._id === questionId);
    if (optionIndex === question.correct && !solvedQuestions.includes(questionId)) {
      // socket.emit('solveQuestion', { questionId, selectedAnswer: optionIndex });
      socket.emit('solveQuestion', { questionId, selectedAnswer: optionIndex, categories: selectedCategories  });
      // Optionally, update backend immediately
    //   await axios.post('/api/solved', { questionId, selectedAnswer: optionIndex});
    }
  };

  const labelImages = {
    // "Natural Science": "path/to/natgeo.jpg",
    // "Geography": "path/to/geography.jpg",
    "History": discoverylogo,
    "Natural Science": natgeologo,
    "Mathematics": codelogo,
    "Biology": natgeologo,
    "Geography": natgeologo,
    "Politics": khanlogo,
    "Number Theory": codelogo,
    "Classic": billlogo,
    "Dystopian": ww2logo,
    "Poetry": ww1logo,
    "American Literature": ww2logo,
    "Modernism": ww3logo,
    // I'll add more as needed
  };


  return (
    <div className="app-container">
      {/* Navigation bar */}
      <div className="navbar">
        <div className="nav-left">
          {/* <span className="solved-counter">{`Community Solved: ${solvedQuestions.length} `}</span> */}
          <span className="solved-counter">Community Solved: </span>
          <span className="count">{`${solvedQuestions.length}`}</span>

        </div>
        <div className="nav-center">


          <div className="category-checkboxes">
            {categoriesList.map((category) => (
              <label key={category}>
                <input
                  type="checkbox"
                  value={category}
                  checked={selectedCategories.includes(category)}
                  onChange={() => handleCategoryChange(category)}
                />
                {category}
              </label>
            ))}
          </div>


          <div className="dropdown">
            <button className='dropdown-btn'>Categories</button>
            <div className="dropdown-content">
              {categoriesList.map((category) => (
                <label key={category}>
                  <input
                    type="checkbox"
                    value={category}
                    checked={selectedCategories.includes(category)}
                    onChange={() => handleCategoryChange(category)}
                  />
                  {category}
                </label>
              ))}
            </div>
          </div>

        </div>

        <div className="nav-right">

        </div>

      </div>

      <div className="cursor-layer">
        {Object.entries(cursors).map(([id, { x, y, username }]) => (
          <div
            key={id}
            className="cursor"
            style={{ left: x, top: y }}
          >
            <div className="cursor-icon">✋</div>
            <span className="cursor-name">{username}</span>
          </div>
        ))}
      </div>


      {/* Grid container */}
      <div className="grid-container">
        {/* {questions.map((q) => (
          <div key={q._id} className={`grid-item ${solvedQuestions.includes(q._id) ? 'correct' : ''}`}>



            <div className="ad-banner">
              <img src={adImage} alt="Advertisement" />
            </div>
            <p>{q.question}</p>
            {q.options.map((option, index) => (
              <label key={index}>
                <input
                  className="radio-input"
                  type="radio"
                  name={`question-${q._id}`}
                  checked={selectedAnswers[q._id] === index}
                  onChange={() => handleAnswerChange(q._id, index)}
                />
                <span className="custom-radio" />
                {option}
              </label>
            ))}
          </div>
        ))} */}

        {questions.map((q) => {
          // const imageUrl = q.labels.find(label => labelImages[label]) ? labelImages[q.labels.find(label => labelImages[label])] : adImage;

          const labels = q.labels || []; // Safeguard against undefined labels
          const imageUrl = labels.find(label => labelImages[label]) ? labelImages[labels.find(label => labelImages[label])] : adImage;

          return (
            <div key={q._id} className={`grid-item ${solvedQuestions.includes(q._id) ? 'correct' : ''}`}>
              <div className="ad-banner">
                <img src={imageUrl} alt="Advertisement" />
              </div>
              <p>{q.question}</p>
              {q.options.map((option, index) => (
                <label key={index}>
                  <input
                    className="radio-input"
                    type="radio"
                    name={`question-${q._id}`}
                    checked={selectedAnswers[q._id] === index}
                    onChange={() => handleAnswerChange(q._id, index)}
                  />
                  <span className="custom-radio" />
                  {option}
                </label>
              ))}
            </div>
          );
        })}
      </div>
    </div>
  );

};


export default App;
